(14, 'Plated Steelcaps', 1200, 'BOOTS', 'Unique – Plating: Reduces incoming damage from all basic attacks by 12% (excluding turret attacks).', 'Plated_Steelcaps_item_HD.webp', NULL, NULL, NULL, 25, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 45, NULL, NULL, NULL),
